function removeDuplicates(s, k) {
    let stack = [];
    for (let c of s) {
        if (stack.length === 0 || stack[stack.length - 1][0] !== c) {
            stack.push([c, 1]);
        } else if (++stack[stack.length - 1][1] === k) {
            stack.pop();
        }
    }
    let result = "";
    for (let pair of stack) {
        result += pair[0].repeat(pair[1]);
    }
    return result;
}
